sqlMap.select:
SELECT distinct count(*) from ( SELECT DISTINCT folder.FOLDER_NAME1 AS FOLDER_NAME1, f.FILE_ID AS FILE_ID, f.FILE_NAME AS FILE_NAME, f.FILE_EXT AS FILE_EXT, f.FOLDER_ID AS FOLDER_ID, f.USE_STATUS AS USE_STATUS, if ( #primary# = '1' , f.CREATE_NAME1, f.CREATE_NAME2) as CREATE_NAME1, f.CREATE_NAME2 as CREATE_NAME2, DATE_ADD(f.CREATE_DATE, INTERVAL #offset# MINUTE) AS CREATE_DATE, f.TENANT_ID AS TENANT_ID, type.TYPE_NAME AS TYPE_NAME from tbl_webfolder_file f inner join ( select * from tbl_webfolder_folder where folder_path like concat(#folderPath# , '%') and tenant_id = #tenantId# and folder_type = #folderType# and use_status = 'Y' ) folder on folder.folder_id = f.folder_id
inner join tbl_webfolder_filetype type ON type.TYPE_ID = f.TYPE_ID and type.tenant_id = f.tenant_id where f.tenant_id = #tenantId# and f.USE_STATUS = 'Y'
) t where 1=1
